const cfg = $('Set workflow config').item.json || {};
const totp = $('Generate TOTP').item.json || {};

const email = typeof cfg.email === 'string' ? cfg.email.trim() : '';
const password = typeof cfg.password === 'string' ? cfg.password : '';
const token = typeof totp.token === 'string' ? totp.token.trim() : '';
const apiBase = typeof cfg.apiBase === 'string' ? cfg.apiBase.replace(/\/+$/, '') : '';
const userAgent = typeof cfg.userAgent === 'string' && cfg.userAgent.trim() ? cfg.userAgent.trim() : 'n8n-airbus-mypayslip/1.0';

let maxDocuments = Number(cfg.maxDocuments);
if (!Number.isFinite(maxDocuments)) maxDocuments = NaN;
if (Number.isFinite(maxDocuments)) maxDocuments = Math.trunc(maxDocuments);

const errors = [];
if (!email) errors.push('email fehlt.');
if (!password) errors.push('password fehlt. Setze AIRBUS_MYPAYSLIP_PASSWORD oder trage den Wert im Set-Node ein.');
if (!token) errors.push('TOTP-Token fehlt. Konfiguriere den Node Generate TOTP mit einem TOTP-Credential.');
if (!apiBase) errors.push('apiBase fehlt.');
if (!Number.isInteger(maxDocuments) || maxDocuments < 0) errors.push('maxDocuments muss eine ganze Zahl >= 0 sein.');

if (errors.length) {
  return [{
    json: {
      kind: 'error',
      ok: false,
      status: 'validation_error',
      action: 'downloadPayslipsToPaperless',
      message: errors.join(' '),
      totalAvailable: 0,
      unseenAvailable: 0,
      selectedCount: 0,
      results: []
    }
  }];
}

return [{
  json: {
    email,
    password,
    token,
    apiBase,
    userAgent,
    maxDocuments,
    action: 'downloadPayslipsToPaperless'
  }
}];

const cfg = $('Validate workflow config').item.json || {};
const response = $json || {};

function shortText(value) {
  return String(value == null ? '' : value).replace(/\s+/g, ' ').trim().slice(0, 260);
}

function parseSetCookie(cookieLine) {
  const first = String(cookieLine || '').split(';')[0];
  const idx = first.indexOf('=');
  if (idx === -1) return null;
  return { name: first.slice(0, idx).trim(), value: first.slice(idx + 1).trim() };
}

function extractSetCookies(headers) {
  const raw = headers?.['set-cookie'] ?? headers?.['Set-Cookie'];
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [String(raw)];
}

const status = Number(response.statusCode || 0);
if (!Number.isFinite(status) || status < 200 || status >= 300) {
  throw new Error(`Login fehlgeschlagen: HTTP ${status}. Antwort: ${shortText(JSON.stringify(response.body ?? ''))}`);
}

const jar = {};
for (const line of extractSetCookies(response.headers)) {
  const parsed = parseSetCookie(line);
  if (parsed) jar[parsed.name] = parsed.value;
}

const cookieHeader = Object.entries(jar).map(([name, value]) => `${name}=${value}`).join('; ');

return [{ json: { ...cfg, cookieHeader } }];

const cfg = $('Build login session').item.json || {};
const response = $json || {};

function shortText(value) {
  return String(value == null ? '' : value).replace(/\s+/g, ' ').trim().slice(0, 260);
}

function parseSetCookie(cookieLine) {
  const first = String(cookieLine || '').split(';')[0];
  const idx = first.indexOf('=');
  if (idx === -1) return null;
  return { name: first.slice(0, idx).trim(), value: first.slice(idx + 1).trim() };
}

function extractSetCookies(headers) {
  const raw = headers?.['set-cookie'] ?? headers?.['Set-Cookie'];
  if (!raw) return [];
  return Array.isArray(raw) ? raw : [String(raw)];
}

const status = Number(response.statusCode || 0);
if (!Number.isFinite(status) || status < 200 || status >= 300) {
  throw new Error(`TOTP-Login fehlgeschlagen: HTTP ${status}. Antwort: ${shortText(JSON.stringify(response.body ?? ''))}`);
}

const jar = {};
for (const chunk of String(cfg.cookieHeader || '').split(';')) {
  const part = chunk.trim();
  if (!part) continue;
  const idx = part.indexOf('=');
  if (idx === -1) continue;
  jar[part.slice(0, idx)] = part.slice(idx + 1);
}
for (const line of extractSetCookies(response.headers)) {
  const parsed = parseSetCookie(line);
  if (parsed) jar[parsed.name] = parsed.value;
}

const cookieHeader = Object.entries(jar).map(([name, value]) => `${name}=${value}`).join('; ');

return [{ json: { ...cfg, cookieHeader } }];

const cfg = $('Build authenticated session').item.json || {};
const response = $json || {};

function shortText(value) {
  return String(value == null ? '' : value).replace(/\s+/g, ' ').trim().slice(0, 260);
}

const status = Number(response.statusCode || 0);
if (!Number.isFinite(status) || status < 200 || status >= 300) {
  throw new Error(`Dokumentenliste laden fehlgeschlagen: HTTP ${status}. Antwort: ${shortText(JSON.stringify(response.body ?? ''))}`);
}

const rawDocuments = Array.isArray(response.body)
  ? response.body
  : Array.isArray(response.body?.data)
    ? response.body.data
    : Array.isArray(response.body?.results)
      ? response.body.results
      : [];

const documents = rawDocuments
  .filter((doc) => doc && doc.itemId != null && doc.documentId != null)
  .slice()
  .sort((a, b) => new Date(b?.insertTime || 0).getTime() - new Date(a?.insertTime || 0).getTime());

const selectedDocuments = cfg.maxDocuments === 0 ? documents : documents.slice(0, cfg.maxDocuments);

if (selectedDocuments.length === 0) {
  return [{
    json: {
      kind: 'noop',
      ok: true,
      status: 'nothing_found',
      action: 'downloadPayslipsToPaperless',
      message: 'Keine Dokumente gefunden.',
      totalAvailable: documents.length,
      unseenAvailable: 0,
      selectedCount: 0,
      results: []
    }
  }];
}

return selectedDocuments.map((doc) => ({
  json: {
    kind: 'document',
    ok: true,
    status: 'selected',
    action: 'downloadPayslipsToPaperless',
    totalAvailable: documents.length,
    unseenAvailable: selectedDocuments.length,
    selectedCount: selectedDocuments.length,
    email: cfg.email,
    maxDocuments: cfg.maxDocuments,
    cookieHeader: cfg.cookieHeader,
    apiBase: cfg.apiBase,
    userAgent: cfg.userAgent,
    itemId: String(doc.itemId),
    documentId: String(doc.documentId),
    documentName: doc.name || null,
    insertTime: doc.insertTime || null,
    isNew: doc.isNew === true,
    customFields: Array.isArray(doc.customFields) ? doc.customFields : [],
    filename: doc.name || null
  }
}));

const source = $('Filter new documents').item.json || {};
const response = $json || {};
const binary = $binary || {};

function shortText(value) {
  return String(value == null ? '' : value).replace(/\s+/g, ' ').trim().slice(0, 260);
}

function extractHeader(headers, name) {
  const wanted = String(name || '').toLowerCase();
  for (const [key, value] of Object.entries(headers || {})) {
    if (String(key).toLowerCase() === wanted) return Array.isArray(value) ? value[0] : value;
  }
  return '';
}

function safeFilePart(value) {
  return String(value || '').replace(/[\/:*?"<>|]+/g, '-').replace(/\s+/g, ' ').trim();
}

function filenameFromDisposition(headers) {
  const contentDisposition = String(extractHeader(headers, 'content-disposition') || '');
  if (!contentDisposition) return '';
  const utf8Match = contentDisposition.match(/filename\*=UTF-8''([^;]+)/i);
  if (utf8Match) {
    try {
      return decodeURIComponent(utf8Match[1]).trim();
    } catch (error) {
      return utf8Match[1].trim();
    }
  }
  const plainMatch = contentDisposition.match(/filename="?([^";]+)"?/i);
  return plainMatch ? plainMatch[1].trim() : '';
}

function extensionFromMimeType(mimeType) {
  const normalized = String(mimeType || '').toLowerCase();
  if (normalized.includes('pdf')) return 'pdf';
  if (normalized.includes('png')) return 'png';
  if (normalized.includes('jpeg') || normalized.includes('jpg')) return 'jpg';
  return 'bin';
}

function fallbackFilename() {
  const preferredName = safeFilePart(source.documentName || source.filename || '');
  const contentType = String(extractHeader(response.headers, 'content-type') || '');
  const ext = extensionFromMimeType(contentType);
  if (preferredName && /\.[A-Za-z0-9]{2,5}$/.test(preferredName)) return preferredName;
  if (preferredName) return `${preferredName}.${ext}`;
  return `airbus-payslip-${safeFilePart(source.documentId || source.itemId || 'document')}.${ext}`;
}

const status = Number(response.statusCode || 0);
if (!Number.isFinite(status) || status < 200 || status >= 300) {
  throw new Error(`Dokument ${source.documentId || 'unknown'} herunterladen fehlgeschlagen: HTTP ${status}. Antwort: ${shortText(response.statusMessage || '')}`);
}

if (!binary.data) {
  throw new Error(`Dokument ${source.documentId || 'unknown'} wurde ohne Binary-Daten geliefert.`);
}

const fileName = filenameFromDisposition(response.headers) || fallbackFilename();
const mimeType = String(extractHeader(response.headers, 'content-type') || binary.data.mimeType || 'application/octet-stream').split(';')[0].trim() || 'application/octet-stream';

return [{
  json: {
    ...source,
    kind: 'document',
    ok: true,
    status: 'downloaded',
    fileName,
    filename: fileName
  },
  binary: {
    data: {
      ...binary.data,
      fileName,
      mimeType
    }
  }
}];

const source = $('Prepare downloaded document').item.json || {};
const upload = $json || {};

const success = upload.isSuccess === true || upload.status === 'success';

return [{
  json: {
    kind: 'result',
    ok: success,
    status: success ? 'uploaded' : 'failed',
    action: 'downloadPayslipsToPaperless',
    documentId: source.documentId || null,
    itemId: source.itemId || null,
    filename: source.filename || upload.filename || null,
    documentName: source.documentName || null,
    insertTime: source.insertTime || null,
    customFields: source.customFields || [],
    totalAvailable: source.totalAvailable || 0,
    unseenAvailable: source.unseenAvailable || 0,
    selectedCount: source.selectedCount || 0,
    paperless: upload,
    errorReason: success ? null : (upload.errorReason || upload.message || 'paperless_upload_failed')
  }
}];

const source = $json || {};

return [{
  json: {
    kind: 'result',
    ok: true,
    status: 'skipped_existing',
    action: 'downloadPayslipsToPaperless',
    documentId: source.documentId || null,
    itemId: source.itemId || null,
    filename: source.filename || null,
    documentName: source.documentName || null,
    insertTime: source.insertTime || null,
    customFields: source.customFields || [],
    totalAvailable: source.totalAvailable || 0,
    unseenAvailable: source.unseenAvailable ?? null,
    selectedCount: source.selectedCount || 0,
    paperless: null,
    errorReason: null
  }
}];

const rows = $input.all().map((item) => item.json || {});

const uploadedCount = rows.filter((row) => row.status === 'uploaded').length;
const skippedCount = rows.filter((row) => row.status === 'skipped_existing').length;
const failedCount = rows.filter((row) => row.status === 'failed').length;
const totalAvailable = rows[0]?.totalAvailable || 0;
const selectedCount = rows[0]?.selectedCount || rows.length;
const newCount = uploadedCount + failedCount;

let status = 'success';
let message = `${uploadedCount} Dokument(e) erfolgreich an Paperless uebergeben.`;

if (failedCount > 0) {
  status = 'partial_failure';
  message = `${uploadedCount} Dokument(e) erfolgreich, ${failedCount} fehlgeschlagen.`;
} else if (uploadedCount === 0 && skippedCount > 0) {
  status = 'nothing_new';
  message = `Keine neuen Dokumente. ${skippedCount} Dokument(e) wurden bereits verarbeitet.`;
} else if (skippedCount > 0) {
  message = `${uploadedCount} neue Dokument(e) erfolgreich, ${skippedCount} bereits verarbeitet.`;
}

return [{
  json: {
    ok: failedCount === 0,
    status,
    action: 'downloadPayslipsToPaperless',
    message,
    totalAvailable,
    unseenAvailable: newCount,
    selectedCount,
    uploadedCount,
    skippedCount,
    failedCount,
    results: rows.map((row) => ({
      documentId: row.documentId || null,
      itemId: row.itemId || null,
      filename: row.filename || null,
      status: row.status || null,
      errorReason: row.errorReason || null
    }))
  }
}];

const data = $json || {};

return [{
  json: {
    ok: data.ok !== false,
    status: data.status || data.kind || 'noop',
    action: data.action || 'downloadPayslipsToPaperless',
    message: data.message || null,
    totalAvailable: data.totalAvailable || 0,
    unseenAvailable: data.unseenAvailable || 0,
    selectedCount: data.selectedCount || 0,
    uploadedCount: 0,
    failedCount: data.ok === false ? 1 : 0,
    results: Array.isArray(data.results) ? data.results : []
  }
}];
